B.JQ=new A.d3("ex_003","Mobilit\xe9 des hanches","Debout, effectuez des cercles de hanches lents dans les deux sens. 10 cercles par direction. Mouvement fluide et contr\xf4l\xe9.",8,"facile","Hanches","mobilite")
B.JR=new A.d3("ex_008","\xc9tirement nuque","Assis ou debout. Inclinez lentement la t\xeate vers l'\xe9paule droite. Maintenez 20 secondes. R\xe9p\xe9tez de l'autre c\xf4t\xe9. 3 fois par c\xf4t\xe9.",5,"facile","Cou / Nuque","etirement")
